parameters.jsCode:
const items = $input.all();

let formattedText = '';

items.forEach((item, index) => {
  const d = item.json;

  const val = (v) => {
    if (v === null || v === undefined || v === '') return 'null';
    if (Array.isArray(v)) return v.length > 0 ? v.join(', ') : 'null';
    return String(v).trim();
  };

  formattedText += `Profile ${index + 1}:\n`;
  formattedText += `City: ${val(d.city)}\n`;
  formattedText += `Country: ${val(d.country)}\n`;
  formattedText += `Full Name: ${val(d.fullName)}\n`;
  formattedText += `Functional: ${val(d.functional)}\n`;
  formattedText += `LinkedIn URL: ${val(d.linkedinUrl)}\n`;
  formattedText += `Org City: ${val(d.orgCity)}\n`;
  formattedText += `Org Industry: ${val(d.orgIndustry)}\n`;
  formattedText += `Org Name: ${val(d.orgName)}\n`;
  formattedText += `Org Size: ${val(d.orgSize)}\n`;
  formattedText += `Org State: ${val(d.orgState)}\n`;
  formattedText += `Org Website: ${val(d.orgWebsite)}\n`;
  formattedText += `Phone: ${val(d.phone)}\n`;
  formattedText += `Position: ${val(d.position)}\n`;
  formattedText += `Seniority: ${val(d.seniority)}\n`;
  formattedText += `-----------------------\n`;
});

return [{ json: { Leads: formattedText } }];

const raw = $input.first().json.text;
const inputItems = $input.all();
const start = raw.indexOf('[');
const end = raw.lastIndexOf(']');
const profiles = JSON.parse(raw.substring(start, end + 1));
const leadsText = $('Collective Data').first().json.Leads;
const linkedinUrls = [...leadsText.matchAll(/LinkedIn URL:\s*(https?:\/\/\S+)/g)].map(m => m[1]);
const fullNames = [...leadsText.matchAll(/Full Name:\s*(.+)/g)].map(m => m[1].trim());
const results = [];
for (let i = 0; i < profiles.length; i++) {
  results.push({
    json: {
      profileIndex: i + 1,
      fullName: fullNames[i] ?? null,
      linkedinUrl: linkedinUrls[i] ?? null,
      connectionMessage: profiles[i]["message"]
    }
  });
}
return results;

const inputItems = $input.all();
const datasetItems = $('Get Collected Information').all();

const capitalize = (s) => (s && s !== 'null') ? s[0].toUpperCase() + s.slice(1) : null;

return inputItems.map((item, i) => {
  const d = datasetItems[i].json;

  return {
    json: {
      ...item.json,
      functional:     capitalize(d.functional),
      orgName:        d.orgName ?? null,
      orgIndustry:    capitalize(d.orgIndustry),
      state:          d.state ?? null,
      orgWebsite:     d.orgWebsite ?? null,
      orgDescription: d.orgDescription ?? null,
      email:          d.email ?? null,
    }
  };
});
